<!doctype html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Misery Index</title><script src="https://cdn.ably.com/lib/ably.min-2.js"></script>
<style>select{background:#18181b;color:#eee;margin:6px 0;padding:12px;width:100%}.transport-grid{display:grid;gap:9px;grid-template-columns:repeat(5,minmax(0,1fr))}.transport-card{background:#121214;border:1px solid #303030;border-radius:10px;color:#eee;margin:0;padding:11px;text-align:left}.transport-card.active{border-color:#777}.transport-card.selected{border-color:#facc15;box-shadow:0 0 0 2px rgba(250,204,21,.22)}.transport-card strong,.transport-card span{display:block}.transport-card strong{text-transform:capitalize}.transport-card span{color:#ddd;font-size:13px;margin-top:5px}.transport-card small{text-transform:uppercase}.transport-badge{background:#292929;border:1px solid #4a4a4a;border-radius:999px;color:#facc15;display:inline-block;font-size:11px;font-weight:900;letter-spacing:.08em;padding:4px 8px;text-transform:uppercase;vertical-align:middle}.transport-badge.polling{color:#d4d4d4}.transport-badge.ably{color:#60a5fa}.transport-badge.reverb{color:#c084fc}.synthetic-badge{background:rgba(249,115,22,.16);border:1px solid #f97316;border-radius:999px;color:#fb923c;display:inline-block;font-size:11px;font-weight:900;letter-spacing:.08em;padding:4px 8px;text-transform:uppercase;vertical-align:middle}@media(max-width:700px){.transport-grid{grid-template-columns:repeat(2,minmax(0,1fr))}}</style>
<style>body{font:16px system-ui;background:#09090b;color:#eee;max-width:980px;margin:40px auto;padding:20px}input,button{box-sizing:border-box;width:100%;padding:12px;margin:6px 0;border-radius:8px;border:1px solid #444}button{background:#facc15;font-weight:800;cursor:pointer}button:disabled{cursor:not-allowed;opacity:.55}button.secondary{background:#262626;color:#eee}button.danger{background:#7f1d1d;border-color:#ef4444;color:#fff}section{border:1px solid #333;padding:16px;border-radius:12px;margin-top:14px}.row{display:flex;gap:8px}.hidden{display:none!important}small,.muted{color:#aaa}.game-row{align-items:center;border-top:1px solid #292929;display:flex;flex-wrap:wrap;gap:12px;padding:10px 0}.game-row:first-child{border-top:0}.game-info{flex:1;min-width:0}.game-info strong,.game-info small{display:block;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.game-actions{display:flex;flex:0 0 auto;gap:7px}.game-actions button{margin:0;padding:10px 12px;width:auto;white-space:nowrap}.available-members{background:#121214;border:1px solid #303030;border-radius:8px;flex:0 0 100%;padding:8px 12px}.available-members span{display:block;padding:3px 0}.player-tabs{display:flex;gap:10px;margin:0 -2px 2px;overflow-x:auto;padding:2px 2px 8px}.player-tab{align-items:center;background:#171717;border:1px solid #404040;border-radius:11px;display:flex;flex:0 0 auto;gap:8px;padding:10px 12px;transition:border-color .2s,background .2s,box-shadow .2s}.player-tab.active{background:rgba(250,204,21,.15);border-color:#facc15;box-shadow:0 0 0 1px rgba(250,204,21,.35)}.player-tab.me{border-style:dashed}.player-dot{border:1px solid rgba(255,255,255,.3);border-radius:50%;height:10px;width:10px}.player-score{background:rgba(0,0,0,.35);border-radius:5px;color:#d4d4d4;font:11px ui-monospace,monospace;padding:3px 6px}.turn-status{color:#facc15;font-size:12px;font-weight:900;letter-spacing:1.5px;margin:0 0 12px;text-transform:uppercase}.turn-status.waiting{color:#a3a3a3}.game-outcome{background:rgba(250,204,21,.12);border:1px solid #facc15;border-radius:12px;color:#facc15;font-size:20px;font-weight:900;letter-spacing:.06em;margin-bottom:14px;padding:16px;text-align:center;text-transform:uppercase}.game-layout{display:grid;gap:18px;grid-template-columns:minmax(0,1fr) 320px}.game-panel{min-width:0}.game-toolbar{display:flex;justify-content:flex-end;margin-bottom:8px}.game-toolbar button{margin:0;width:auto}.chat-panel{background:#111113;border:1px solid #353535;border-radius:12px;display:flex;flex-direction:column;height:470px;min-height:0;overflow:hidden}.chat-head{align-items:center;border-bottom:1px solid #333;display:flex;justify-content:space-between;padding:13px 14px}.chat-head strong{letter-spacing:.08em;text-transform:uppercase}.chat-head small{color:#facc15}.chat-messages{display:flex;flex:1;flex-direction:column;gap:7px;overflow-y:auto;padding:12px}.chat-empty{align-items:center;color:#777;display:flex;flex:1;justify-content:center;text-align:center}.chat-row{display:flex;flex-direction:column;max-width:84%}.chat-row.own{align-self:flex-end}.chat-row.other{align-self:flex-start}.chat-bubble{background:#1d1d20;border:1px solid #363636;border-radius:12px 12px 12px 3px;padding:7px 9px}.chat-row.own .chat-bubble{background:#facc15;border-color:#facc15;border-radius:12px 12px 3px 12px;color:#09090b}.chat-row.own .chat-time{color:rgba(9,9,11,.58)}.chat-author{font-size:11px;font-weight:900;margin-bottom:2px}.chat-copy{overflow-wrap:anywhere}.chat-time{color:#777;font-size:9px;margin-left:7px;white-space:nowrap}.chat-line{align-items:flex-end;display:flex}.chat-form{align-items:center;background:#0d0d0f;border-top:1px solid #333;display:flex;gap:7px;padding:9px}.chat-input-wrap{flex:1;position:relative}.chat-form input{background:#1d1d20;color:#fff;margin:0;padding-right:42px}.chat-count{bottom:11px;color:#777;font-size:9px;position:absolute;right:10px}.chat-form button{border-radius:50%;height:42px;margin:0;padding:0;width:42px}.error-modal{align-items:center;background:rgba(0,0,0,.82);display:flex;inset:0;justify-content:center;padding:20px;position:fixed;z-index:100}.error-card{background:#18181b;border:1px solid #ef4444;border-radius:14px;box-shadow:0 20px 60px #000;padding:20px;width:min(380px,100%)}.error-card h2{color:#f87171;margin-top:0}.error-card p{color:#ddd;overflow-wrap:anywhere}@media(max-width:760px){body{margin-top:12px}.game-layout{grid-template-columns:1fr}.chat-panel{height:420px}}@media(max-width:560px){.game-info{flex-basis:100%}.game-actions{width:100%}.game-actions button{flex:1}}</style></head>
<body><h1>Misery Index</h1><section id="transportState"><h2>Live transport state</h2><p class="muted">Loading current player allocation...</p></section><section id="entry"><input id="name" placeholder="Your name"><div class="row"><button onclick="createGame()">Create game</button><button id="join" onclick="joinGame()">Join game</button></div><input id="code" placeholder="Room code"><div id="available"><h2>Rooms</h2><p class="muted">Loading rooms...</p></div></section><section id="room" class="hidden"><h2>Room <span id="roomCode"></span> <span id="roomTransport" class="transport-badge"></span> <span id="roomSynthetic" class="synthetic-badge hidden">Synthetic</span> <span id="spectatorBadge" class="transport-badge hidden">Spectator</span></h2><div id="players"></div><button id="start" onclick="startGame()">Start and deal 3</button><button id="roomExit" class="secondary" onclick="exitGameView()">Leave room</button><button id="deleteRoom" class="danger hidden" onclick="deleteRoom()">Kill and delete room</button></section><section id="game" class="hidden"><div class="game-toolbar"><span id="gameSynthetic" class="synthetic-badge hidden">Synthetic</span><button id="playAgain" class="secondary hidden" onclick="playAgain()">Play again</button><button id="gameExit" class="danger" onclick="exitGameView()">Leave room</button></div><div id="gameOutcome" class="game-outcome hidden"></div><div class="game-layout"><div class="game-panel"><div id="playerTabs" class="player-tabs"></div><p id="turnStatus" class="turn-status"></p><h2 id="card"></h2><small id="answerPrompt">Is this card placed correctly?</small><div id="stealActions" class="row hidden"><button onclick="acceptSteal()">Try to steal</button><button class="secondary" onclick="passSteal()">Pass</button></div><div id="answerActions" class="row"><button onclick="move(true)">Correct</button><button onclick="move(false)">Wrong</button></div><div id="moves"></div></div><aside class="chat-panel"><div class="chat-head"><strong>Game chat</strong><small id="chatMode">Same room</small></div><div id="chatMessages" class="chat-messages"></div><form id="chatForm" class="chat-form" onsubmit="sendChat(event)"><div class="chat-input-wrap"><input id="chatInput" maxlength="20" autocomplete="off" placeholder="Message" oninput="updateChatCount()"><span id="chatCount" class="chat-count">0/20</span></div><button id="chatSend" type="submit" aria-label="Send message">&#10148;</button></form></aside></div></section><p id="message"></p><div id="errorModal" class="error-modal hidden" role="dialog" aria-modal="true"><div class="error-card"><h2>Request failed</h2><p id="errorMessage"></p><button onclick="closeApiError()">Close</button></div></div>
<script>
const api='{{ url('/api') }}',csrfToken=@json(csrf_token()),realtimeStatusUrl='{{ route('simulator.realtime-status') }}',simulatorRoomsUrl='{{ route('simulator.rooms') }}',simulatorRoomDeleteUrl=@json(route('admin.simulator.rooms.destroy',['game'=>'__GAME__'])),simulatorRoomBotsUrl=@json(route('simulator.rooms.bots.store',['game'=>'__GAME__']));let game=null,user=null,spectatorMode=false,rematchLobby=false,joinPending=false,movePending=false,chatPending=false,lastChatId=null,lastRealtimeEventId=0,acceptedStealOfferKey=null,pollTimer=null,pollRunning=false,realtimeCleanup=null,realtimeIdentity='',realtimeReady=false,strictRealtime=false,realtimeRefreshPending=false,heartbeatTimer=null,selectedTransport='all';const q=id=>document.getElementById(id);
const simulatorStacks=@json($stacks);const packSelect=document.createElement('select');packSelect.id='pack';packSelect.setAttribute('aria-label','Game pack');(simulatorStacks.length?simulatorStacks:[{name:'Normal',slug:'normal'}]).forEach(stack=>{const option=document.createElement('option');option.value=stack.slug;option.textContent='Game pack: '+stack.name;packSelect.appendChild(option)});q('name').insertAdjacentElement('afterend',packSelect);
async function call(path,options={}){const r=await fetch(api+path,{headers:{'Content-Type':'application/json','Accept':'application/json'},...options});const text=await r.text();const j=text?JSON.parse(text):null;if(!r.ok)throw Error(j?.message||'Request failed');return j?.data??j}
async function callAbsolute(url,options={}){const r=await fetch(url,{...options,headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrfToken,...options.headers}});const text=await r.text();const j=text?JSON.parse(text):null;if(!r.ok)throw Error(j?.message||'Request failed');return j?.data??j}
function showApiError(error){q('errorMessage').textContent=error?.message||String(error)||'Request failed';q('errorModal').classList.remove('hidden')}
function closeApiError(){q('errorModal').classList.add('hidden')}
function transportName(driver){return ({pusher:'Pusher',ably:'Ably',polling:'Polling',reverb:'Reverb'})[driver]||'Polling'}
function transportBadge(driver){const safe=['pusher','ably','polling','reverb'].includes(driver)?driver:'polling';return '<span class="transport-badge '+safe+'">'+transportName(safe)+'</span>'}
function syntheticBadge(isSynthetic){return isSynthetic?'<span class="synthetic-badge">Synthetic</span>':''}
async function loadTransportStatus(){try{const response=await fetch(realtimeStatusUrl,{headers:{Accept:'application/json'}});if(!response.ok)throw Error('Status unavailable');const status=await response.json();const providers=status.providers||{};const activeTotal=Object.values(providers).reduce((total,item)=>total+Number(item?.active_players||0),0);const order=['all','pusher','ably','polling','reverb'];q('transportState').innerHTML='<h2>Live transport state</h2><p class="muted">Mode: '+escapeHtml(status.mode==='reverb_override'?'Strict Reverb override':transportName(status.primary_provider)+' first, hosted fallback enabled')+'</p><div class="transport-grid">'+order.map(name=>{if(name==='all')return '<button type="button" data-transport="all" onclick="selectTransport(\'all\')" class="transport-card '+(selectedTransport==='all'?'selected':'')+'"><strong>Sve</strong><small>automatic allocation</small><span>'+escapeHtml(activeTotal)+' active players</span></button>';const item=providers[name]||{};const limit=item.limit===null||item.limit===undefined?'No app limit':escapeHtml(item.limit);const remaining=item.remaining===null||item.remaining===undefined?'':(' &middot; '+escapeHtml(item.remaining)+' free');return '<button type="button" data-transport="'+name+'" onclick="selectTransport(\''+name+'\')" class="transport-card '+(item.state==='active'||item.primary?'active ':'')+(selectedTransport===name?'selected':'')+'"><strong>'+transportName(name)+'</strong><small>'+escapeHtml(item.state||'unknown')+(item.primary?' &middot; primary':'')+'</small><span>'+escapeHtml(item.active_players||0)+' active / '+limit+remaining+'</span></button>'}).join('')+'</div>'}catch(e){q('transportState').innerHTML='<h2>Live transport state</h2><p class="muted">Could not load transport state. Retrying...</p>'}}
function selectTransport(driver){selectedTransport=['all','pusher','ably','polling','reverb'].includes(driver)?driver:'all';document.querySelectorAll('[data-transport]').forEach(card=>card.classList.toggle('selected',card.dataset.transport===selectedTransport));void loadAvailableGames()}
function stopRealtime(){if(realtimeCleanup){try{realtimeCleanup()}catch(e){console.warn('Realtime cleanup failed',e)}}realtimeCleanup=null;realtimeReady=false;realtimeIdentity='';if(heartbeatTimer)clearInterval(heartbeatTimer);heartbeatTimer=null}
function startHeartbeat(interval){if(heartbeatTimer)clearInterval(heartbeatTimer);heartbeatTimer=setInterval(()=>{if(game&&user)void call('/games/'+game.id+'/heartbeat',{method:'POST',body:JSON.stringify({user_id:user.id,after_event_id:lastRealtimeEventId})}).then(applyRealtimePayload).catch(error=>console.warn('Simulator heartbeat failed',error))},Math.max(10000,Number(interval)||20000))}
function applyRealtimePayload(update){if(!game||!update||Number(update.game_id)!==Number(game.id))return;if(update.deleted||!update.state){resetSession();return}const state=update.state;const cardCache=new Map;Object.values(game.hands||{}).flat().forEach(card=>cardCache.set(Number(card.id),card));if(state.current_card)cardCache.set(Number(state.current_card.id),state.current_card);(update.events||[]).forEach(event=>{lastRealtimeEventId=Math.max(lastRealtimeEventId,Number(event.id)||0);const card=event.payload?.card;if(card)cardCache.set(Number(card.id),card)});const hands={};Object.entries(state.hand_card_ids||{}).forEach(([memberId,ids])=>{hands[memberId]=ids.map(id=>cardCache.get(Number(id))||{id:Number(id),score:0,title:'Card'}).sort((a,b)=>Number(a.score)-Number(b.score))});const knownMoveIds=new Set((game.moves||[]).map(move=>Number(move.id)));const newMoves=(update.events||[]).filter(event=>event.type==='MOVE_RESULT'&&!knownMoveIds.has(Number(event.id))).map(event=>({id:Number(event.id),correct:Boolean(event.payload?.correct),player:{name:event.payload?.player_name||'Player'},card:event.payload?.card||null}));game={...game,...state,hands,current_card:state.current_card,moves:[...newMoves,...(game.moves||[])],chat_messages:update.chat_message?[...(game.chat_messages||[]).filter(message=>Number(message.id)!==Number(update.chat_message.id)),update.chat_message]:(game.chat_messages||[])};render()}
function refreshFromRealtime(){if(pollRunning){realtimeRefreshPending=true;return}pollRunning=true;refresh(true).catch(error=>console.warn('Simulator realtime refresh failed',error)).finally(()=>{pollRunning=false;if(realtimeRefreshPending){realtimeRefreshPending=false;refreshFromRealtime()}})}
function connectPusherProtocol(config,driver){let socket=null,retryTimer=null,stopped=false;const connect=()=>{if(stopped)return;const secure=driver==='pusher'||config.scheme!=='http';const standardPort=secure?443:80;const port=Number(config.port)||standardPort;const authority=config.host+(port===standardPort?'':':'+port);const base=driver==='pusher'?'wss://ws-'+encodeURIComponent(config.cluster)+'.pusher.com':'ws'+(secure?'s':'')+'://'+authority;socket=new WebSocket(base+'/app/'+encodeURIComponent(config.key)+'?protocol=7&client=misery-simulator&version=1.0&flash=false');socket.onmessage=message=>{try{const payload=JSON.parse(message.data);if(payload.event==='pusher:connection_established'){socket.send(JSON.stringify({event:'pusher:subscribe',data:{auth:'',channel:config.channel}}));realtimeReady=true;startHeartbeat(config.heartbeat_interval_ms);return}if(payload.event===config.event)applyRealtimePayload(typeof payload.data==='string'?JSON.parse(payload.data):payload.data)}catch(error){console.warn('Simulator realtime message failed',error)}};socket.onerror=()=>socket?.close();socket.onclose=()=>{realtimeReady=false;if(stopped)return;if(driver==='reverb')retryTimer=setTimeout(connect,3000);else console.warn('Simulator Pusher unavailable; polling fallback active')}};connect();realtimeCleanup=()=>{stopped=true;if(retryTimer)clearTimeout(retryTimer);if(socket&&socket.readyState<2)socket.close()}}
async function connectAbly(config){if(!window.Ably)throw Error('Ably browser SDK did not load');const client=new window.Ably.Realtime({authCallback:async(_params,callback)=>{try{const token=await call('/games/'+game.id+'/realtime-token?user_id='+encodeURIComponent(user.id));callback(null,token)}catch(error){callback(error,null)}}});const channel=client.channels.get(config.channel);const onUpdate=message=>applyRealtimePayload(message.data);await channel.subscribe(config.event,onUpdate);realtimeReady=true;startHeartbeat(config.heartbeat_interval_ms);realtimeCleanup=()=>{channel.unsubscribe(config.event,onUpdate);void channel.detach().catch(()=>undefined);client.close()}}
function configureRealtime(){if(!game||!user)return;const driver=game.sync_driver||'polling';strictRealtime=driver==='reverb';const config=driver==='pusher'?game.pusher:driver==='ably'?game.ably:driver==='reverb'?game.reverb:null;if(!config){stopRealtime();strictRealtime=driver==='reverb';return}const identity=driver+':'+config.channel;if(identity===realtimeIdentity)return;stopRealtime();strictRealtime=driver==='reverb';realtimeIdentity=identity;if(strictRealtime)startHeartbeat(config.heartbeat_interval_ms);if(driver==='ably'){void connectAbly(config).catch(error=>{realtimeReady=false;console.warn('Simulator Ably unavailable; polling fallback active',error)});return}connectPusherProtocol(config,driver)}
async function createGame(){try{const payload={name:q('name').value,stack:q('pack').value};if(selectedTransport!=='all')payload.sync_driver=selectedTransport;set(await call('/games',{method:'POST',body:JSON.stringify(payload)}))}catch(e){showApiError(e)}}
async function joinGame(){
 if(joinPending)return;
 try{
  const code=q('code').value.trim().toUpperCase();if(!code)throw Error('Enter a room code.');
  joinPending=true;setJoinDisabled(true);
  set(await call('/games/code/'+encodeURIComponent(code)+'/join',{method:'POST',body:JSON.stringify({name:q('name').value})}));
 }catch(e){joinPending=false;setJoinDisabled(false);showApiError(e)}
}
async function quickJoin(code){q('code').value=code;await joinGame()}
function setJoinDisabled(disabled){q('join').disabled=disabled;document.querySelectorAll('.quick-join').forEach(button=>button.disabled=disabled)}
async function loadAvailableGames(){
 if(game)return;
 try{
  const allGames=await callAbsolute(simulatorRoomsUrl);const games=selectedTransport==='all'?allGames:allGames.filter(room=>(room.sync_driver||'polling')===selectedTransport);
  q('available').innerHTML='<h2>Rooms</h2>'+(games.length?games.map(x=>{const state=x.winner_id?'FINISHED':x.started?'IN GAME':'OPEN';const canAddBots=!x.started&&x.members.length===1&&!x.members.some(member=>member.is_bot);const botOptions=Array.from({length:7},(_,index)=>'<option value="'+(index+1)+'">'+(index+1)+'</option>').join('');return '<div class="game-row"><div class="game-info"><strong>'+escapeHtml(x.members[0]?.name||'Game room')+' '+syntheticBadge(x.is_synthetic)+' '+transportBadge(x.sync_driver)+'</strong><small>'+escapeHtml(x.code)+' &middot; '+x.members.length+'/8 players &middot; '+state+' &middot; '+transportName(x.sync_driver)+' transport</small></div><div class="game-actions"><button onclick="openSpectator('+Number(x.id)+')">Watch</button><button class="secondary" onclick="toggleRoomMembers('+Number(x.id)+',this)">Members</button><button class="danger" onclick="killAvailableRoom('+Number(x.id)+')">Kill</button>'+(canAddBots?'<select id="bot-count-'+Number(x.id)+'" aria-label="Number of bots" style="margin:0;padding:9px;width:auto">'+botOptions+'</select><button class="secondary" onclick="addBots('+Number(x.id)+')">Add bots</button>':'')+(!x.started?'<button class="quick-join" onclick="quickJoin(\''+escapeHtml(x.code)+'\')">Join</button>':'')+'</div><div id="available-members-'+Number(x.id)+'" class="available-members hidden">'+x.members.map(member=>'<span>'+escapeHtml(member.name)+(member.is_bot?' (BOT)':'')+'</span>').join('')+'</div></div>'}).join(''):'<p class="muted">No active rooms right now.</p>');
 }catch(e){q('available').innerHTML='<h2>Rooms</h2><p class="muted">Could not load rooms. Retrying...</p>'}
}
function toggleRoomMembers(id,button){const list=q('available-members-'+id);if(!list)return;const opening=list.classList.contains('hidden');list.classList.toggle('hidden');button.textContent=opening?'Hide members':'Members'}
async function openSpectator(id){try{stopRealtime();game=await callAbsolute(simulatorRoomsUrl+'/'+encodeURIComponent(id));user=null;spectatorMode=true;q('entry').className='hidden';q('room').className='';render()}catch(e){showApiError(e)}}
async function killAvailableRoom(id){if(!confirm('Kill and permanently delete this room?'))return;try{await callAbsolute(simulatorRoomDeleteUrl.replace('__GAME__',encodeURIComponent(id)),{method:'DELETE'});await loadAvailableGames()}catch(e){showApiError(e)}}
async function addBots(id){const count=Number(q('bot-count-'+id)?.value||1);if(!confirm('Add '+count+' autonomous '+(count===1?'bot':'bots')+' to this open lobby?'))return;try{await callAbsolute(simulatorRoomBotsUrl.replace('__GAME__',encodeURIComponent(id)),{method:'POST',body:JSON.stringify({count})});await loadAvailableGames()}catch(e){showApiError(e)}}
function escapeHtml(value){return String(value).replace(/[&<>'"]/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[char]))}
function playerColor(value){return ({yellow:'#facc15',blue:'#60a5fa',emerald:'#10b981',purple:'#c084fc',rose:'#ef4444',red:'#ef4444',orange:'#f97316',brown:'#8b5a2b',silver:'#d4d4d4'})[value]||'#facc15'}
function messageTime(value){const date=new Date(value);return Number.isNaN(date.getTime())?'':date.toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'})}
function renderChat(){const messages=game.chat_messages||[];const latest=messages.length?Number(messages[messages.length-1].id):null;const shouldScroll=latest!==lastChatId;lastChatId=latest;q('chatMessages').innerHTML=messages.length?messages.map(message=>{const own=!spectatorMode&&Number(message.user_id)===Number(user?.id);const author=message.user?.name||'Player';return '<div class="chat-row '+(own?'own':'other')+'"><div class="chat-bubble">'+(!own?'<div class="chat-author" style="color:'+playerColor(message.user?.color)+'">'+escapeHtml(author)+'</div>':'')+'<div class="chat-line"><span class="chat-copy">'+escapeHtml(message.message)+'</span><span class="chat-time">'+escapeHtml(messageTime(message.created_at))+'</span></div></div></div>'}).join(''):'<div class="chat-empty">No messages yet.</div>';if(shouldScroll)q('chatMessages').scrollTop=q('chatMessages').scrollHeight}
function updateChatCount(){q('chatCount').textContent=q('chatInput').value.length+'/20'}
function set(x){spectatorMode=false;game=x.game.data||x.game;user=x.user.data||x.user;q('entry').className='hidden';q('room').className='';render();configureRealtime()}
async function refresh(snapshot=false){if(!game)return;if(spectatorMode)game=await callAbsolute(simulatorRoomsUrl+'/'+encodeURIComponent(game.id));else if(user)game=await call('/games/'+game.id+(snapshot?'/snapshot':'?user_id='+encodeURIComponent(user.id)));render();if(!spectatorMode)configureRealtime()}
function render(){
 q('roomCode').textContent=game.code;
 q('roomTransport').className='transport-badge '+(game.sync_driver||'polling');q('roomTransport').textContent=transportName(game.sync_driver);
 q('roomSynthetic').className=game.is_synthetic?'synthetic-badge':'synthetic-badge hidden';q('gameSynthetic').className=game.is_synthetic?'synthetic-badge':'synthetic-badge hidden';
 q('players').innerHTML=game.members.map(x=>'<p>'+escapeHtml(x.name)+'</p>').join('');
 q('spectatorBadge').className=spectatorMode?'transport-badge':'transport-badge hidden';q('roomExit').textContent=spectatorMode?'Back to rooms':'Leave room';q('gameExit').textContent=spectatorMode?'Back to rooms':'Leave room';q('gameExit').className=spectatorMode?'secondary':'danger';
 const isOwner=!spectatorMode&&Number(game.owner_id)===Number(user?.id);
 q('start').style.display=isOwner?'block':'none';
 q('deleteRoom').className=isOwner?'danger':'danger hidden';
 if(rematchLobby){q('room').className='';q('game').className='hidden';q('players').innerHTML=game.members.filter(x=>(game.lobby_member_ids||[]).map(Number).includes(Number(x.id))).map(x=>'<p>'+escapeHtml(x.name)+'</p>').join('');return}
 if(!game.started)return;
 q('room').className='hidden';q('game').className='';q('card').textContent=game.current_card?.title||'No more cards';
 const activeId=Number(game.current_player_id);const isMyTurn=!spectatorMode&&activeId===Number(user?.id);const activePlayer=game.members.find(x=>Number(x.id)===activeId);const winner=game.members.find(x=>Number(x.id)===Number(game.winner_id));
 q('playerTabs').innerHTML=game.members.map(x=>{const active=!game.winner_id&&Number(x.id)===activeId;const mine=!spectatorMode&&Number(x.id)===Number(user?.id);const points=(game.hands?.[x.id]||[]).length;return '<div class="player-tab'+(active?' active':'')+(mine?' me':'')+'"><span class="player-dot" style="background:'+playerColor(x.color)+'"></span><strong>'+escapeHtml(x.name)+'</strong><span class="player-score">'+points+' pts</span></div>'}).join('');
 q('gameOutcome').className=game.winner_id?'game-outcome':'game-outcome hidden';q('gameOutcome').textContent=game.winner_id?'Game finished — '+(winner?.name||'Winner')+' won':'';
 q('playAgain').className=!spectatorMode&&game.winner_id?'secondary':'secondary hidden';
 const stealOfferKey=game.is_steal_turn&&isMyTurn?game.id+':'+activeId+':'+(game.current_card?.id||'no-card'):null;const stealAccepted=Boolean(stealOfferKey&&acceptedStealOfferKey===stealOfferKey);const stealOfferVisible=Boolean(stealOfferKey&&!stealAccepted&&!spectatorMode&&!game.winner_id);
 q('turnStatus').textContent=game.winner_id?'Game finished':activePlayer?(isMyTurn?(game.is_steal_turn?(stealAccepted?'Your steal attempt':'Steal offered to you'):'Your turn'):(game.is_steal_turn?activePlayer.name+' can steal':activePlayer.name+"'s turn")):'Waiting for next turn';
 if(movePending&&isMyTurn)q('turnStatus').textContent='Submitting move...';
 q('turnStatus').className='turn-status'+(isMyTurn?'':' waiting');
 q('answerPrompt').textContent=stealOfferVisible?'Do you want to try to steal this card?':'Is this card placed correctly?';q('answerPrompt').className=spectatorMode||game.winner_id?'hidden':'';
 q('stealActions').className=stealOfferVisible?'row':'row hidden';q('stealActions').querySelectorAll('button').forEach(button=>button.disabled=movePending);
 q('answerActions').className=spectatorMode||game.winner_id||stealOfferVisible?'row hidden':'row';
 q('answerActions').querySelectorAll('button').forEach(button=>button.disabled=!isMyTurn||movePending);
 q('moves').innerHTML=game.moves.map(x=>'<p>'+escapeHtml(x.player.name)+': '+(x.correct?'Correct':'Wrong')+'</p>').join('');
 q('chatForm').className=spectatorMode?'chat-form hidden':'chat-form';q('chatMode').textContent=spectatorMode?'Read only':'Same room';renderChat();
}
async function sendChat(event){event.preventDefault();if(chatPending||!game||!user)return;const message=q('chatInput').value.trim();if(!message)return;chatPending=true;q('chatSend').disabled=true;try{const sent=await call('/games/'+game.id+'/messages',{method:'POST',body:JSON.stringify({user_id:user.id,message})});game.chat_messages=[...(game.chat_messages||[]),sent];q('chatInput').value='';updateChatCount();renderChat()}catch(e){showApiError(e)}finally{chatPending=false;q('chatSend').disabled=false}}
function resetSession(){stopRealtime();strictRealtime=false;game=null;user=null;spectatorMode=false;rematchLobby=false;joinPending=false;movePending=false;chatPending=false;lastChatId=null;lastRealtimeEventId=0;acceptedStealOfferKey=null;q('room').className='hidden';q('game').className='hidden';q('entry').className='';q('chatInput').value='';updateChatCount();setJoinDisabled(false);q('code').value=''}
async function playAgain(){if(!game||!user||!game.winner_id)return;try{game=await call('/games/'+game.id+'/lobby-presence',{method:'POST',body:JSON.stringify({user_id:user.id,present:true})});rematchLobby=true;render()}catch(e){showApiError(e)}}
async function exitGameView(){if(spectatorMode){resetSession();await loadAvailableGames();return}await leaveRoom()}
async function leaveRoom(){if(!game||!user)return;if(!confirm(Number(game.owner_id)===Number(user.id)?'Leave and end this room for everyone?':'Leave this room?'))return;try{await call('/games/'+game.id+'/leave',{method:'POST',body:JSON.stringify({user_id:user.id})});resetSession();await loadAvailableGames()}catch(e){showApiError(e)}}
async function deleteRoom(){if(!game||!user||Number(game.owner_id)!==Number(user.id))return;if(!confirm('Kill and permanently delete this room?'))return;try{await call('/games/'+game.id,{method:'DELETE',body:JSON.stringify({user_id:user.id})});resetSession();await loadAvailableGames()}catch(e){showApiError(e)}}
async function startGame(){try{game=await call('/games/'+game.id+'/start',{method:'POST',body:JSON.stringify({user_id:user.id,stack:q('pack').value,target_score:5})});rematchLobby=false;render()}catch(e){showApiError(e)}}
function acceptSteal(){if(!game||!user||!game.is_steal_turn||Number(game.current_player_id)!==Number(user.id))return;acceptedStealOfferKey=game.id+':'+user.id+':'+(game.current_card?.id||'no-card');render()}
async function passSteal(){if(movePending||!game||!user||!game.is_steal_turn||Number(game.current_player_id)!==Number(user.id))return;movePending=true;render();try{const x=await call('/games/'+game.id+'/pass-steal',{method:'POST',body:JSON.stringify({player_id:user.id})});game=x.game?.data||x.game||x;acceptedStealOfferKey=null}catch(e){showApiError(e)}finally{movePending=false;render()}}
async function move(correct){if(movePending||!game||!user)return;const offerKey=game.id+':'+user.id+':'+(game.current_card?.id||'no-card');if(game.is_steal_turn&&acceptedStealOfferKey!==offerKey)return;movePending=true;render();try{const x=await call('/games/'+game.id+'/moves',{method:'POST',body:JSON.stringify({player_id:user.id,correct})});game=x.game.data||x.game;acceptedStealOfferKey=null} catch(e){showApiError(e)}finally{movePending=false;render()}}
async function pollApp(){if(pollRunning)return;pollRunning=true;try{await loadTransportStatus();if(game){if(spectatorMode||!realtimeReady)await refresh(false)}else await loadAvailableGames()}catch(e){if(game)console.warn('Simulator refresh failed',e)}finally{pollRunning=false;const delay=game?(spectatorMode||!realtimeReady?3000:20000):3000;pollTimer=setTimeout(pollApp,delay)}}
void pollApp();
</script></body></html>
